#[test]
fn altchunk_without_rid_preserved_opaquely() {
    let body = r#"<w:p><w:r><w:t>Kept.</w:t></w:r></w:p><w:altChunk/><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ECMA-376 §A.1 (CT_AltChunk r:id use=optional): an altChunk with no r:id is schema-valid; \
         Word opens without repair",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Kept.",
        "ECMA-376 §17.17.2.1 'If this attribute is omitted, the parent element shall be ignored' — \
         an unexpanded/ignored altChunk contributes no text; accepted text is only the real \
         paragraph"
    );
}

