#[test]
fn two_altchunk_anchors_each_preserve_own_rid() {
    let body = r#"<w:altChunk r:id="rId10"/><w:altChunk r:id="rId11"/><w:p><w:r><w:t>End.</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ECMA-376 §A.1 (altChunk maxOccurs=unbounded): two consecutive anchors are schema-valid; \
         Word opens without repair",
    );
    let xml = reserialize(&b);
    assert!(
        xml.contains("rId10"),
        "ECMA-376 §17.17.2.1: the first anchor's r:id must survive round-trip so its import target \
         stays resolvable. document.xml:\n{xml}"
    );
    assert!(
        xml.contains("rId11"),
        "ECMA-376 §17.17.2.1: the second anchor's distinct r:id must independently survive \
         round-trip — anchors must not be merged or collapsed. document.xml:\n{xml}"
    );
}

#[test]
fn altchunk_unrecognized_content_type_contributes_no_text() {
    let body =
        r#"<w:p><w:r><w:t>Only this.</w:t></w:r></w:p><w:altChunk r:id="rId12"/><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Only this.",
        "ECMA-376 §17.17.2.1 + MS-OI29500 §2.1.527: a non-importing/unprocessable altChunk is \
         ignored and contributes no text; accepted text is only the real paragraph"
    );

    let rejected = Document::parse(&b)
        .expect("parse")
        .read_rejected()
        .expect("read_rejected")
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Only this.",
        "MS-OI29500 §2.1.527: the altChunk anchor carries no tracked-change markup and contributes \
         no text either way; reject-all text is unchanged from the real paragraph"
    );
}

#[test]
fn altchunk_without_rid_is_ignored_and_opens_clean() {
    let body = r#"<w:altChunk/><w:p><w:r><w:t>Only real text</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "ECMA-376 §A.1 (CT_AltChunk r:id use=optional): an anchor without r:id is schema-valid; \
         Word opens without repair",
    );
    let accepted = Document::parse(&b)
        .expect("parse")
        .read_accepted()
        .expect("read_accepted")
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Only real text",
        "ECMA-376 §17.17.2.1: an altChunk with the id attribute omitted shall be ignored, so it \
         contributes no text; accept-all reads only the real paragraph"
    );
}
